import base64
from django.http import HttpResponse, HttpResponseBadRequest
from django.contrib.auth import login
from django.contrib.auth.models import User
from django.views.decorators.csrf import csrf_exempt
from xml.etree import ElementTree as ET

def parse_saml_response(encoded_saml_response):
    decoded = base64.b64decode(encoded_saml_response)
    try:
        return ET.fromstring(decoded)
    except ET.ParseError:
        return None

def extract_user_info(saml_xml):
    ns = {'saml': 'urn:oasis:names:tc:SAML:2.0:assertion'}
    assertion = saml_xml.find('.//saml:Assertion', ns)
    if assertion is None:
        return None
    name_id = assertion.find('.//saml:Subject/saml:NameID', ns).text
    attributes = {}
    for attr in assertion.findall('.//saml:AttributeStatement/saml:Attribute', ns):
        attr_name = attr.attrib.get('Name')
        attr_value = attr.find('.//saml:AttributeValue', ns).text
        attributes[attr_name] = attr_value
    return name_id, attributes

@csrf_exempt
def saml_acs(request):
    saml_response = request.POST.get('SAMLResponse')
    if not saml_response:
        return HttpResponseBadRequest("No SAMLResponse in POST data")

    saml_xml = parse_saml_response(saml_response)
    if saml_xml is None:
        return HttpResponseBadRequest("Invalid SAML Response")

    user_info = extract_user_info(saml_xml)
    if user_info is None:
        return HttpResponseBadRequest("Could not extract user info from SAML Assertion")

    name_id, attributes = user_info

    user, created = User.objects.get_or_create(username=name_id)
    if created:
        user.email = attributes.get('email', '')
        user.first_name = attributes.get('firstName', '')
        user.last_name = attributes.get('lastName', '')
        user.save()

    login(request, user)

    # Redirect to a success page
    return HttpResponse("Login Successful")

